@RestController
public class FileUploadController {

    @PostMapping("/upload")
    public String uploadFile(@RequestParam("file") MultipartFile file) throws IOException {
        // Validate the file type and content
        if (!isValidFileType(file)) {
            throw new IllegalArgumentException("Invalid file type");
        }
        if (!isValidContent(file)) {
            throw new IllegalArgumentException("Invalid file content");
        }

        // Generate a unique filename for the uploaded file
        String fileName = UUID.randomUUID().toString() + "_" + file.getOriginalFilename();

        // Store the uploaded file in a public directory
        Path path = Paths.get("uploads", fileName);
        Files.copy(file.getInputStream(), path, StandardCopyOption.REPLACE_EXISTING);

        // Return the URL of the uploaded file
        return "http://localhost:8080/uploads/" + fileName;
    }

    private boolean isValidFileType(MultipartFile file) {
        String contentType = file.getContentType();
        if (contentType == null || !contentType.startsWith("image")) {
            return false;
        }
        return true;
    }

    private boolean isValidContent(MultipartFile file) throws IOException {
        // Check the size of the uploaded file
        long size = file.getSize();
        if (size > 10 * 1024 * 1024) { // 10 MB
            return false;
        }

        // Check the content of the uploaded file
        byte[] bytes = file.getBytes();
        for (int i = 0; i < bytes.length; i++) {
            if (bytes[i] == 0) {
                return false;
            }
        }
        return true;
    }
}